form:Form.form:Scripts:
		function ChangePer()
{	
	if(Ctrl('oi_personal_emp').GetXValue() != "") 
		Ctrl('main').DoEvent("CHANGE");
}

function RefreshControls()
{
	//Desactivo los Controles de Cambio
	if (MyHORSel==null)
	{
		CtrlEnabled("DATA"  , false);
		CtrlEnabled("ADD"   , true );
		CtrlEnabled("EDIT"  , false);		
		CtrlEnabled("DELETE", false);
		CtrlEnabled("BACK"  , true );
		CtrlEnabled("ACCEPT", false);
		CtrlEnabled("CANCEL", false);
	} 
	else if (Edit)
	{
		CtrlEnabled("DATA"  , true );
		CtrlEnabled("ADD"   , false);
		CtrlEnabled("EDIT"  , false);
		CtrlEnabled("SAVE"  , false);
		CtrlEnabled("DELETE", false);
		CtrlEnabled("BACK"  , false);
		CtrlEnabled("ACCEPT", true );
		CtrlEnabled("CANCEL", true );
	} 
	else
	{
		CtrlEnabled("DATA"  , false);
		CtrlEnabled("ADD"   , true );
		CtrlEnabled("EDIT"  , true );
		CtrlEnabled("SAVE"  , true );
		CtrlEnabled("DELETE", true );
		CtrlEnabled("BACK"  , true );
		CtrlEnabled("ACCEPT", false);
		CtrlEnabled("CANCEL", false);
	}
}
